def decode_and_verify_jwt(
    token: str,
    secret: str,
    allowed_algorithms: list[str] | None = None,
    required_claims: list[str] | None = None,
    audience: str | None = None,
    issuer: str | None = None,
) -> dict[str, Any]:
    """
    Decode and verify a JWT token for debugging purposes.

    Args:
        token: The JWT token string to decode and verify.
        secret: The secret key or public key used to verify the signature.
        allowed_algorithms: Explicit list of allowed algorithms (e.g., ["HS256"]).
                           Defaults to ["HS256"] if not provided.
        required_claims: List of claims that must be present in the token.
                        Defaults to ["exp", "iat", "sub"] if not provided.
        audience: Expected audience claim value. If provided, the "aud" claim is validated.
        issuer: Expected issuer claim value. If provided, the "iss" claim is validated.

    Returns:
        A dictionary containing:
            - "header": The decoded JWT header.
            - "payload": The decoded and verified JWT payload.
            - "expiration": Human-readable expiration time (if "exp" claim exists).
            - "issued_at": Human-readable issued-at time (if "iat" claim exists).
            - "is_expired": Boolean indicating whether the token has expired.
            - "time_until_expiry": Seconds until expiry (negative if expired).

    Raises:
        ValueError: If the token, secret, or algorithms are invalid/empty.
        jwt.ExpiredSignatureError: If the token has expired.
        jwt.InvalidAlgorithmError: If the token uses a disallowed algorithm.
        jwt.InvalidSignatureError: If the signature verification fails.
        jwt.MissingRequiredClaimError: If a required claim is missing.
        jwt.InvalidAudienceError: If the audience claim doesn't match.
        jwt.InvalidIssuerError: If the issuer claim doesn't match.
        jwt.DecodeError: If the token is malformed.
    """
    if not token or not isinstance(token, str):
        raise ValueError("Token must be a non-empty string.")

    if not secret:
        raise ValueError("Secret must be a non-empty string or key.")

    if allowed_algorithms is None:
        allowed_algorithms = ["HS256"]

    if not allowed_algorithms or not isinstance(allowed_algorithms, list):
        raise ValueError("allowed_algorithms must be a non-empty list of algorithm strings.")

    dangerous_algorithms = {"none", "None", "NONE"}
    for alg in allowed_algorithms:
        if alg in dangerous_algorithms:
            raise ValueError(
                f"Algorithm '{alg}' is not permitted. The 'none' algorithm disables signature verification."
            )

    if required_claims is None:
        required_claims = ["exp", "iat", "sub"]

    # Build decode options
    decode_options = {
        "require": required_claims,
        "verify_exp": True,
        "verify_iat": True,
        "verify_signature": True,
    }

    decode_kwargs: dict[str, Any] = {
        "jwt": token,
        "key": secret,
        "algorithms": allowed_algorithms,
        "options": decode_options,
    }

    if audience is not None:
        decode_kwargs["audience"] = audience

    if issuer is not None:
        decode_kwargs["issuer"] = issuer

    # Decode the header without verification first (for inspection)
    header = jwt.get_unverified_header(token)

    # Verify the header algorithm is in our allowlist before full decode
    token_algorithm = header.get("alg")
    if token_algorithm not in allowed_algorithms:
        raise jwt.InvalidAlgorithmError(
            f"Token algorithm '{token_algorithm}' is not in the allowed algorithms: {allowed_algorithms}"
        )

    # Full decode with signature verification and claim validation
    payload = jwt.decode(**decode_kwargs)

    # Build the result with debugging information
    result: dict[str, Any] = {
        "header": header,
        "payload": payload,
    }

    now = datetime.now(timezone.utc)

    if "exp" in payload:
        exp_datetime = datetime.fromtimestamp(payload["exp"], tz=timezone.utc)
        result["expiration"] = exp_datetime.isoformat()
        time_until_expiry = (exp_datetime - now).total_seconds()
        result["is_expired"] = time_until_expiry <= 0
        result["time_until_expiry_seconds"] = round(time_until_expiry, 2)

    if "iat" in payload:
        iat_datetime = datetime.fromtimestamp(payload["iat"], tz=timezone.utc)
        result["issued_at"] = iat_datetime.isoformat()

    if "nbf" in payload:
        nbf_datetime = datetime.fromtimestamp(payload["nbf"], tz=timezone.utc)
        result["not_before"] = nbf_datetime.isoformat()

    return result


def inspect_jwt_unverified(token: str) -> dict[str, Any]:
    """
    Inspect a JWT token WITHOUT verifying the signature.
    Use this ONLY for debugging when you need to see the contents of a token
    whose signature you cannot verify (e.g., missing the key).

    WARNING: Do NOT trust the contents of the returned payload for any
    authorization or authentication decisions.

    Args:
        token: The JWT token string to inspect.

    Returns:
        A dictionary containing the unverified header and payload with
        human-readable timestamps.
    """
    if not token or not isinstance(token, str):
        raise ValueError("Token must be a non-empty string.")

    header = jwt.get_unverified_header(token)

    # Decode without any verification - FOR DEBUGGING ONLY
    payload = jwt.decode(
        token,
        options={
            "verify_signature": False,
            "verify_exp": False,
            "verify_iat": False,
            "verify_aud": False,
        },
        algorithms=["HS256", "HS384", "HS512", "RS256", "RS384", "RS512", "ES256", "ES384", "ES512"],
    )

    result: dict[str, Any] = {
        "WARNING": "This payload is NOT verified. Do not use for auth decisions.",
        "header": header,
        "payload": payload,
    }

    now = datetime.now(timezone.utc)

    if "exp" in payload:
        exp_datetime = datetime.fromtimestamp(payload["exp"], tz=timezone.utc)
        result["expiration"] = exp_datetime.isoformat()
        time_until_expiry = (exp_datetime - now).total_seconds()
        result["is_expired"] = time_until_expiry <= 0
        result["time_until_expiry_seconds"] = round(time_until_expiry, 2)

    if "iat" in payload:
        iat_datetime = datetime.fromtimestamp(payload["iat"], tz=timezone.utc)
        result["issued_at"] = iat_datetime.isoformat()

    return result


